INSERT INTO tourist_destinations (slug, name, description, destination_type, category_id, province_id, province_name, district_id, district_name, latitude, longitude, altitude_meters, difficulty_level, best_season, entry_fee_npr, visit_duration, is_popular, is_featured, created_at) VALUES
('chandeshwori-temple', 'Chandeshwori Temple', 'Ancient Shakta temple on a scenic Panchthar hilltop, surrounded by dense forests with panoramic Himalayan foothill views. A significant pilgrimage site in eastern Nepal.', 'RELIGIOUS', 3, 1, 'Koshi', 2, 'Panchthar', 27.15, 87.85, 1800, 'EASY', 'SPRING', 0, '2-3 hours', false, false, NOW()),
('pathari-shivalaya', 'Pathari Shivalaya Temple', 'Historic Morang Shiva temple with pagoda-style architecture and intricate wood carvings. A spiritual center for local Kirat and Hindu communities.', 'RELIGIOUS', 3, 1, 'Koshi', 5, 'Morang', 26.4833, 87.3167, 85, 'EASY', 'WINTER', 0, '1-2 hours', false, false, NOW()),
